const url = $input.item.json.body.url;
if (!url || !url.match(/^https?:\/\//)) {
  throw new Error('invalid url');
}
return [{
  json: {
    source_platform: 'manual',
    source_url: url,
    source_excerpt: $input.item.json.body.notes || null,
    source_author: null,
  }
}];

// Soft-block list — domains/handles where we know engagement is unwelcome
// or against community policy. Items matching these patterns are dropped at
// discover time so the auto-draft pipeline never spends Anthropic tokens or
// reviewer attention on them. Operators can still manually engage by visiting
// the URL directly; this filter only stops the automation.
//
// To add a soft-block, add a row to SOFT_BLOCK_PATTERNS. The `pattern` is
// matched against source_url AND source_author. The `reason` is logged for
// audit visibility.
//
// NOTE: this Code node is duplicated on the manual-webhook path (Normalize
// Input -> Apply Soft Block -> Insert Outreach Item) and the RSS path
// (Normalize RSS -> Apply Soft Block RSS -> Insert RSS Item). Keep the
// SOFT_BLOCK_PATTERNS list in sync between the two.
const SOFT_BLOCK_PATTERNS = [
  { pattern: /(?:^|\.)annerallen\.com/i,           reason: 'AI-skeptical single author; manual engagement only' },
  { pattern: /countercraft\.substack\.com/i,       reason: 'Lincoln Michel — AI-skeptical commentary; manual only' },
  { pattern: /reddit\.com\/r\/writing/i,           reason: 'r/writing rule 3 bans AI-tool mentions' },
];

const out = [];
for (const item of items) {
  const j = item.json || {};
  const url = String(j.source_url || '');
  const author = String(j.source_author || '');
  const haystack = url + ' ' + author;
  const hit = SOFT_BLOCK_PATTERNS.find(p => p.pattern.test(haystack));
  if (hit) {
    console.log(`[Apply Soft Block] DROPPED ${url} (${hit.reason})`);
    continue;
  }
  out.push(item);
}
return out;

// Unwrap follow.it tracking proxies. The Creative Penn (and any other publisher
// who delegated their feed to follow.it) emits items with link AND guid both
// pointing at https://api.follow.it/track-rss-story-click/v3/<opaque>?utm_source=follow.it.
// The canonical URL is recoverable via a single HTTP 302: the redirect Location
// header carries it as `?q=<urlencoded>`. We only HEAD api.follow.it/* hosts;
// non-tracking URLs pass through untouched.
async function unwrapFollowIt(url) {
  try {
    if (!url || !/^https:\/\/api\.follow\.it\//.test(url)) return url;
    const res = await fetch(url, { method: 'HEAD', redirect: 'manual', signal: AbortSignal.timeout(3000) });
    const loc = res.headers.get('location');
    if (!loc) return url;
    const m = loc.match(/[?&]q=([^&]+)/);
    if (!m) return url;
    const decoded = decodeURIComponent(m[1]);
    return /^https?:\/\//.test(decoded) ? decoded : url;
  } catch (_) {
    return url;
  }
}

const out = [];
for (const item of items) {
  out.push({
    json: {
      source_platform: 'rss',
      source_url: await unwrapFollowIt(item.json.link),
      source_excerpt: (item.json.contentSnippet || '').slice(0, 1000),
      source_author: item.json.creator || null,
    },
  });
}
return out;

